class Solution {
    public boolean canMakeSubsequence(String str1, String str2) {
        int[] count = new int[26];
        for (char c : str1.toCharArray()) {
            count[c - 'a']++;
        }
        int j = 0;
        for (char c : str2.toCharArray()) {
            boolean found = false;
            for (int i = c - 'a'; i < 26; i++) {
                if (count[i] > 0) {
                    count[i]--;
                    found = true;
                    break;
                }
            }
            if (!found) {
                return false;
            }
            j++;
        }
        return true;
    }
}
